const analysis = $json.analysis;

const errors = [];
const reviewReasons = [];

const allowedCategories = new Set([
  'interview',
  'scene_dialogue',
  'b_roll',
  'performance_take',
  'false_start_or_mistake',
  'empty_or_unusable',
  'mixed',
  'needs_human_review',
]);

const timePattern = /^\d{2}:[0-5]\d:[0-5]\d$/;

function addReviewReason(reason) {
  if (reason && !reviewReasons.includes(reason)) {
    reviewReasons.push(reason);
  }
}

if (!analysis || typeof analysis !== 'object' || Array.isArray(analysis)) {
  errors.push('Missing or invalid analysis object');
} else {
  // Normalize common confidence-score formats.
  // Examples: 0.9 becomes 90, "0.9" becomes 90, and 87.6 becomes 88.
  if (
    typeof analysis.confidence_score === 'string' &&
    analysis.confidence_score.trim() !== '' &&
    Number.isFinite(Number(analysis.confidence_score))
  ) {
    analysis.confidence_score = Number(analysis.confidence_score);
  }

  if (
    typeof analysis.confidence_score === 'number' &&
    Number.isFinite(analysis.confidence_score)
  ) {
    if (
      analysis.confidence_score > 0 &&
      analysis.confidence_score <= 1
    ) {
      analysis.confidence_score = Math.round(
        analysis.confidence_score * 100
      );
    } else {
      analysis.confidence_score = Math.round(
        analysis.confidence_score
      );
    }
  }

  // Required non-empty text fields
  for (const field of [
    'overall_category',
    'content_summary',
    'visual_description',
  ]) {
    if (
      typeof analysis[field] !== 'string' ||
      analysis[field].trim() === ''
    ) {
      errors.push(`${field} is missing or empty`);
    }
  }

  // Required fields that may contain an empty string
  for (const field of [
    'spoken_content_summary',
    'mistake_summary',
    'review_reason',
  ]) {
    if (typeof analysis[field] !== 'string') {
      errors.push(`${field} must be text`);
    }
  }

  // Validate category
  if (!allowedCategories.has(analysis.overall_category)) {
    errors.push('overall_category contains an unsupported value');
  }

  // Required arrays
  for (const field of [
    'searchable_keywords',
    'visual_keywords',
    'spoken_terms',
    'people_or_subjects',
    'locations_or_settings',
    'usable_ranges',
    'segments',
  ]) {
    if (!Array.isArray(analysis[field])) {
      errors.push(`${field} must be an array`);
    }
  }

  // Required true/false fields
  for (const field of [
    'mistake_detected',
    'empty_or_unusable',
    'human_review_required',
  ]) {
    if (typeof analysis[field] !== 'boolean') {
      errors.push(`${field} must be true or false`);
    }
  }

  // Validate normalized confidence score
  if (
    !Number.isInteger(analysis.confidence_score) ||
    analysis.confidence_score < 0 ||
    analysis.confidence_score > 100
  ) {
    errors.push(
      'confidence_score must be a whole number from 0 to 100'
    );
  }

  // Validate spoken terms
  if (Array.isArray(analysis.spoken_terms)) {
    analysis.spoken_terms.forEach((item, index) => {
      if (
        !item ||
        typeof item.term !== 'string' ||
        item.term.trim() === ''
      ) {
        errors.push(`spoken_terms[${index}] has no valid term`);
      }

      if (
        !item ||
        typeof item.timestamp !== 'string' ||
        !timePattern.test(item.timestamp)
      ) {
        errors.push(
          `spoken_terms[${index}] has an invalid timestamp`
        );
      }
    });
  }

  // Validate usable ranges
  if (Array.isArray(analysis.usable_ranges)) {
    analysis.usable_ranges.forEach((range, index) => {
      if (
        !range ||
        typeof range.start_time !== 'string' ||
        !timePattern.test(range.start_time)
      ) {
        errors.push(
          `usable_ranges[${index}] has an invalid start time`
        );
      }

      if (
        !range ||
        typeof range.end_time !== 'string' ||
        !timePattern.test(range.end_time) ||
        range.end_time === '00:00:00'
      ) {
        errors.push(
          `usable_ranges[${index}] has an invalid end time`
        );
      }

      if (
        !range ||
        typeof range.reason !== 'string' ||
        range.reason.trim() === ''
      ) {
        errors.push(`usable_ranges[${index}] has no reason`);
      }
    });
  }

  // Human-review rules
  if (analysis.human_review_required === true) {
    addReviewReason(
      analysis.review_reason || 'The AI requested human review'
    );
  }

  if (
    Number.isInteger(analysis.confidence_score) &&
    analysis.confidence_score < 80
  ) {
    addReviewReason(
      `Low confidence score: ${analysis.confidence_score}`
    );
  }

  if (analysis.overall_category === 'mixed') {
    addReviewReason('The clip contains mixed footage types');
  }

  if (analysis.overall_category === 'needs_human_review') {
    addReviewReason('The clip could not be classified confidently');
  }

  if (analysis.overall_category === 'false_start_or_mistake') {
    addReviewReason('The clip is primarily a false start or mistake');
  }

  if (analysis.mistake_detected === true) {
    addReviewReason(
      analysis.mistake_summary || 'A possible mistake was detected'
    );
  }

  if (
    analysis.empty_or_unusable === true ||
    analysis.overall_category === 'empty_or_unusable'
  ) {
    addReviewReason(
      'The clip may be empty or unusable and requires confirmation'
    );
  }

  if (
    Array.isArray(analysis.usable_ranges) &&
    analysis.usable_ranges.length === 0
  ) {
    addReviewReason('No usable footage range was identified');
  }
}

const valid = errors.length === 0;
const needsReview = !valid || reviewReasons.length > 0;

let processingStatus = 'Complete';

if (!valid) {
  processingStatus = 'Processing Error';
} else if (needsReview) {
  processingStatus = 'Needs Review';
}

const reviewReasonText = !valid
  ? `Validation failed: ${errors.join('; ')}`
  : reviewReasons.join('; ');

return {
  json: {
    ...$json,
    validation: {
      valid,
      errors,
      needs_review: needsReview,
      review_reasons: reviewReasons,
      review_reason_text: reviewReasonText,
      processing_status: processingStatus,
    },
  },
};
